mapper.select:
/* 사용자 권한 목록 조회 login.selectAdminGubunList */
SELECT DISTINCT
    IF(B.ETC1 IS NOT NULL AND TRIM(B.ETC1) != '', B.ETC1, A.AUTH_GUBUN) AS AUTH_GUBUN
FROM ${dbId}.COM_ADMIN A
JOIN ${dbId}.V_COM_CODE B
    ON A.AUTH_GUBUN = B.CODE_ID
   AND B.CODE_GRP_ID = '018'


WHERE A.COMP_ID = #{compId}
  AND A.USER_ID = #{userId}
UNION ALL
SELECT '99' FROM DUAL
/* 일반사용자는 등록된 직원 모두 해당되도록 처리 */

/* 서비스 사용여부 조회 login.selectServiceUseYn */
SELECT 'Y' AS USE_YN
FROM COM_COMPINFO
WHERE COMP_ID = #{compId}

/* 로그인 실패 횟수 조회 login.selectLoginFailCnt */
SELECT IFNULL(LOGIN_FAIL_CNT, 0)
FROM ${dbId}.TB_USER
WHERE USER_ID = #{userId}

mapper.update:
/* 로그인 실패 횟수 증가 login.updateLoginFailCnt */
UPDATE ${dbId}.TB_USER
SET LOGIN_FAIL_CNT = IFNULL(LOGIN_FAIL_CNT, 0) + 1
WHERE USER_ID = #{userId}

/* 계정 잠금 처리 login.lockUser */
UPDATE ${dbId}.TB_USER
SET
    ACCT_STATUS_CD = '003',
    LOCK_DT = NOW()
WHERE USER_ID = #{userId}

mapper.insert:
/* 회원가입 사용자 등록 login.insertUser */
INSERT INTO ${dbId}.TB_USER (
    USER_ID
    , USER_NM
    , EMAIL
    , PASSWD
    , PHONE
    , ORG_ID
    , USE_YN
    , LOGIN_FAIL_CNT
    , TWO_FA_YN
    , ACCT_STATUS_CD
    , CREATE_DT
    , MODIFY_DT
    , CRTR_ID
    , MDFR_ID
) VALUES (
    #{userId}
    , #{userNm}
    , #{email}
    , #{passwd}
    , #{phone}
    , #{orgId}
    , 'Y'
    , 0
    , 'N'
    , '001'
    , NOW()
    , NULL
    , #{userId}
    , NULL
)

/* OTP인증정보 등록 login.insertOTPAuth */
INSERT INTO COM_OTP_AUTH (
    COMP_ID,
    USER_ID,
    OTP_IMG,
    OTP_KEY
) VALUES (
    #{compId},
    #{userId},
    #{otpImg},
    #{otpKey}
)

mapper.update:
/* OTP인증일시 업데이트 login.updateOTPReqDt */
UPDATE COM_OTP_AUTH
SET REQ_DT = NOW()
WHERE COMP_ID = #{compId}
  AND USER_ID = #{userId}

mapper.select:
/* 사용 가능한 토큰여부 login.selectAvailableTokenYn */
SELECT CASE WHEN COUNT(1) = 0 THEN 'Y' ELSE 'N' END
FROM ${dbId}.TB_AUDIT_LOGIN
WHERE LOGIN_TP = 'LOGIN'
  AND USER_ID = #{userId}
  AND TOKEN = #{token}

/* 전체 관리자 확인 여부 login.selectAuth */
SELECT AUTH_GUBUN
FROM COM_ADMIN
WHERE USER_ID = #{userId}
  AND AUTH_GUBUN = '01'

/* IP 목록 조회 login.selectIpList */
SELECT ALLOW_IP
FROM COM_ACCESS_ACL
WHERE USER_ID = #{userId}

/* 이전 비밀번호 목록 조회 login.beforePwdList */
SELECT PASSWD
FROM COM_USERINFO_PW_CHANGE
WHERE USER_ID = #{userId}
ORDER BY SEQ DESC
LIMIT ${limit}

/* 비밀번호 변경 주기 조회 login.pwCnt */
SELECT PW_CNT
FROM COM_COMPINFO
WHERE COMP_ID = #{compId}
